// FindFlight retrieves a single record by primary key
// If cols is empty Find will return all columns.
func FindFlight(ctx context.Context, exec bob.Executor, IDPK uuid.UUID, cols ...string) (*Flight, error) {
	if len(cols) == 0 {
		return Flights.Query(
			sm.Where(Flights.Columns.ID.EQ(psql.Arg(IDPK))),
		).One(ctx, exec)
	}

	return Flights.Query(
		sm.Where(Flights.Columns.ID.EQ(psql.Arg(IDPK))),
		sm.Columns(Flights.Columns.Only(cols...)),
	).One(ctx, exec)
}

