func (os FlightSlice) FlightRouteVersions(mods ...bob.Mod[*dialect.SelectQuery]) FlightRouteVersionsQuery {
	pkID := make(pgtypes.Array[uuid.UUID], 0, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}
		pkID = append(pkID, o.ID)
	}
	PKArgExpr := psql.Select(sm.Columns(
		psql.F("unnest", psql.Cast(psql.Arg(pkID), "uuid[]")),
	))

	return FlightRouteVersions.Query(append(mods,
		sm.Where(psql.Group(FlightRouteVersions.Columns.FlightID).OP("IN", PKArgExpr)),
	)...)
}

func insertFlightFlightRouteVersions0(ctx context.Context, exec bob.Executor, flightRouteVersions1 []*FlightRouteVersionSetter, flight0 *Flight) (FlightRouteVersionSlice, error) {
	for i := range flightRouteVersions1 {
		flightRouteVersions1[i].FlightID = omit.From(flight0.ID)
	}

	ret, err := FlightRouteVersions.Insert(bob.ToMods(flightRouteVersions1...)).All(ctx, exec)
	if err != nil {
		return ret, fmt.Errorf("insertFlightFlightRouteVersions0: %w", err)
	}

	return ret, nil
}

func attachFlightFlightRouteVersions0(ctx context.Context, exec bob.Executor, count int, flightRouteVersions1 FlightRouteVersionSlice, flight0 *Flight) (FlightRouteVersionSlice, error) {
	setter := &FlightRouteVersionSetter{
		FlightID: omit.From(flight0.ID),
	}

	err := flightRouteVersions1.UpdateAll(ctx, exec, *setter)
	if err != nil {
		return nil, fmt.Errorf("attachFlightFlightRouteVersions0: %w", err)
	}

	return flightRouteVersions1, nil
}

func (flight0 *Flight) InsertFlightRouteVersions(ctx context.Context, exec bob.Executor, related ...*FlightRouteVersionSetter) error {
	if len(related) == 0 {
		return nil
	}

	var err error

	flightRouteVersions1, err := insertFlightFlightRouteVersions0(ctx, exec, related, flight0)
	if err != nil {
		return err
	}

	flight0.R.FlightRouteVersions = append(flight0.R.FlightRouteVersions, flightRouteVersions1...)

	for _, rel := range flightRouteVersions1 {
		rel.R.Flight = flight0
	}
	return nil
}

func (flight0 *Flight) AttachFlightRouteVersions(ctx context.Context, exec bob.Executor, related ...*FlightRouteVersion) error {
	if len(related) == 0 {
		return nil
	}

	var err error
	flightRouteVersions1 := FlightRouteVersionSlice(related)

	_, err = attachFlightFlightRouteVersions0(ctx, exec, len(related), flightRouteVersions1, flight0)
	if err != nil {
		return err
	}

	flight0.R.FlightRouteVersions = append(flight0.R.FlightRouteVersions, flightRouteVersions1...)

	for _, rel := range related {
		rel.R.Flight = flight0
	}

	return nil
}

