func (o *Flight) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "FlightRouteVersions":
		rels, ok := retrieved.(FlightRouteVersionSlice)
		if !ok {
			return fmt.Errorf("flight cannot load %T as %q", retrieved, name)
		}

		o.R.FlightRouteVersions = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Flight = o
			}
		}
		return nil
	default:
		return fmt.Errorf("flight has no relationship %q", name)
	}
}

