type flightThenLoader[Q orm.Loadable] struct {
	FlightRouteVersions func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
}

func buildFlightThenLoader[Q orm.Loadable]() flightThenLoader[Q] {
	type FlightRouteVersionsLoadInterface interface {
		LoadFlightRouteVersions(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}

	return flightThenLoader[Q]{
		FlightRouteVersions: thenLoadBuilder[Q](
			"FlightRouteVersions",
			func(ctx context.Context, exec bob.Executor, retrieved FlightRouteVersionsLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadFlightRouteVersions(ctx, exec, mods...)
			},
		),
	}
}

// LoadFlightRouteVersions loads the flight's FlightRouteVersions into the .R struct
func (o *Flight) LoadFlightRouteVersions(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.FlightRouteVersions = nil

	related, err := o.FlightRouteVersions(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, rel := range related {
		rel.R.Flight = o
	}

	o.R.FlightRouteVersions = related
	return nil
}

// LoadFlightRouteVersions loads the flight's FlightRouteVersions into the .R struct
func (os FlightSlice) LoadFlightRouteVersions(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	flightRouteVersions, err := os.FlightRouteVersions(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.FlightRouteVersions = nil
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range flightRouteVersions {

			if !(o.ID == rel.FlightID) {
				continue
			}

			rel.R.Flight = o

			o.R.FlightRouteVersions = append(o.R.FlightRouteVersions, rel)
		}
	}

	return nil
}

type flightJoins[Q dialect.Joinable] struct {
	typ                 string
	FlightRouteVersions modAs[Q, flightRouteVersionColumns]
}

func (j flightJoins[Q]) aliasedAs(alias string) flightJoins[Q] {
	return buildFlightJoins[Q](buildFlightColumns(alias), j.typ)
}

func buildFlightJoins[Q dialect.Joinable](cols flightColumns, typ string) flightJoins[Q] {
	return flightJoins[Q]{
		typ: typ,
		FlightRouteVersions: modAs[Q, flightRouteVersionColumns]{
			c: FlightRouteVersions.Columns,
			f: func(to flightRouteVersionColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, FlightRouteVersions.Name().As(to.Alias())).On(
						to.FlightID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
